#ifndef GQA_RAGGED_PREFILL_CAUSAL_H32_KV8_D128_KERNEL_H_
#define GQA_RAGGED_PREFILL_CAUSAL_H32_KV8_D128_KERNEL_H_

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <cstdint>

// CUDA kernel declaration
__global__ void gqa_ragged_prefill_causal_h32_kv8_d128_kernel(
    const __nv_bfloat16* __restrict__ q,    // [total_q, 32, 128]
    const __nv_bfloat16* __restrict__ k,    // [total_kv, 8, 128]
    const __nv_bfloat16* __restrict__ v,    // [total_kv, 8, 128]
    const int32_t* __restrict__ qo_indptr,  // [len_indptr]
    const int32_t* __restrict__ kv_indptr,  // [len_indptr]
    int32_t len_indptr,
    float sm_scale,
    __nv_bfloat16* __restrict__ out,        // [total_q, 32, 128]
    float* __restrict__ lse                 // [total_q, 32]
);

// Host launcher (implemented in kernel.cu)
void launch_gqa_ragged_prefill_causal_h32_kv8_d128(
    const __nv_bfloat16* q,
    const __nv_bfloat16* k,
    const __nv_bfloat16* v,
    const int32_t* qo_indptr,
    const int32_t* kv_indptr,
    int32_t len_indptr,
    float sm_scale,
    __nv_bfloat16* out,
    float* lse,
    cudaStream_t stream);

#endif  // GQA_RAGGED_PREFILL_CAUSAL_H32_KV8_D128_KERNEL_H_

#include "kernel.h"
#include <cmath>
#include <stdint.h>
#include <math_constants.h>

#ifndef FULL_MASK
#define FULL_MASK 0xffffffffu
#endif

// Warp-wide sum reduction (assumes 32 threads per warp)
static __forceinline__ __device__ float warp_sum(float v) {
  v += __shfl_down_sync(FULL_MASK, v, 16);
  v += __shfl_down_sync(FULL_MASK, v, 8);
  v += __shfl_down_sync(FULL_MASK, v, 4);
  v += __shfl_down_sync(FULL_MASK, v, 2);
  v += __shfl_down_sync(FULL_MASK, v, 1);
  return v;
}

__global__ __launch_bounds__(256, 2)
void gqa_ragged_prefill_causal_h32_kv8_d128_kernel(
    const __nv_bfloat16* __restrict__ q,    // [total_q, 32, 128]
    const __nv_bfloat16* __restrict__ k,    // [total_kv, 8, 128]
    const __nv_bfloat16* __restrict__ v,    // [total_kv, 8, 128]
    const int32_t* __restrict__ qo_indptr,  // [len_indptr]
    const int32_t* __restrict__ kv_indptr,  // [len_indptr]
    int32_t len_indptr,
    float sm_scale,
    __nv_bfloat16* __restrict__ out,        // [total_q, 32, 128]
    float* __restrict__ lse                 // [total_q, 32]
) {
  // One block per sequence segment (len_indptr - 1)
  const int b = blockIdx.x;
  if (b >= (len_indptr - 1)) return;

  const int warp_id = threadIdx.x >> 5;
  const int lane_id = threadIdx.x & 31;
  const int WARPS_PER_BLOCK = blockDim.x >> 5;

  // Fetch segment ranges
  const int32_t q_start  = qo_indptr[b];
  const int32_t q_end    = qo_indptr[b + 1];
  const int32_t kv_start = kv_indptr[b];
  const int32_t kv_end   = kv_indptr[b + 1];

  const int32_t q_len  = q_end - q_start;
  const int32_t kv_len = kv_end - kv_start;

  if (q_len <= 0) {
    return;
  }

  const int total_pairs = q_len * 32;  // (query_index, qo_head) pairs
  // Precompute constants
  const float INV_LOG2 = 1.4426950408889634f;  // 1 / ln(2)
  const int HEAD_DIM = 128;
  const int KV_STRIDE = 8 * HEAD_DIM; // elements to jump one token for a fixed kv head
  const int D_PER_LANE = 4;
  const int d0 = lane_id * D_PER_LANE;

  for (int pair_idx = warp_id; pair_idx < total_pairs; pair_idx += WARPS_PER_BLOCK) {
    const int qi = pair_idx / 32;   // query index within this segment
    const int h  = pair_idx % 32;   // qo head
    const int kv_h = h >> 2;        // map to kv head (GQA ratio = 4)

    // Load Q fragment (4 bfloat16 -> 4 float), pre-scale by sm_scale once
    const int64_t q_off = ((int64_t)(q_start + qi) * 32 + h) * HEAD_DIM + d0;
    const __nv_bfloat16* q_ptr = q + q_off;
    const __nv_bfloat162 q01 = *reinterpret_cast<const __nv_bfloat162*>(q_ptr);
    const __nv_bfloat162 q23 = *reinterpret_cast<const __nv_bfloat162*>(q_ptr + 2);
    const float2 q01f = __bfloat1622float2(q01);
    const float2 q23f = __bfloat1622float2(q23);
    float qv0 = q01f.x * sm_scale;
    float qv1 = q01f.y * sm_scale;
    float qv2 = q23f.x * sm_scale;
    float qv3 = q23f.y * sm_scale;

    // Causal limit: can attend to keys [0, min(qi + 1 + (kv_len - q_len), kv_len))
    const int delta = kv_len - q_len;
    int limit = delta + qi + 1;
    if (limit > kv_len) limit = kv_len;

    // Fast path for no valid keys
    if (limit <= 0) {
      const int64_t out_off = ((int64_t)(q_start + qi) * 32 + h) * HEAD_DIM + d0;
      __nv_bfloat16* out_ptr = out + out_off;
      const __nv_bfloat162 z01 = __floats2bfloat162_rn(0.0f, 0.0f);
      const __nv_bfloat162 z23 = __floats2bfloat162_rn(0.0f, 0.0f);
      *reinterpret_cast<__nv_bfloat162*>(out_ptr)       = z01;
      *reinterpret_cast<__nv_bfloat162*>(out_ptr + 2)   = z23;

      if (lane_id == 0) {
        const int64_t lse_off = ((int64_t)(q_start + qi) * 32 + h);
        lse[lse_off] = -CUDART_INF_F;
      }
      continue;
    }

    float m = -CUDART_INF_F;  // running max of logits
    float s = 0.0f;           // running sum of exp(logits - m)

    // Accumulator for output (per-lane 4 dims)
    float acc0 = 0.0f;
    float acc1 = 0.0f;
    float acc2 = 0.0f;
    float acc3 = 0.0f;

    // Prepare K/V pointers and stride along tokens for fixed kv head and lane dim offset
    const int64_t kv_base_off = ((int64_t)kv_start * 8 + kv_h) * HEAD_DIM + d0;
    const __nv_bfloat16* k_ptr = k + kv_base_off;
    const __nv_bfloat16* v_ptr = v + kv_base_off;

    // Iterate over valid keys
    #pragma unroll 1
    for (int j = 0; j < limit; ++j) {
      // Load K fragment (4 bf16 -> 4 f32)
      const __nv_bfloat162 k01 = *reinterpret_cast<const __nv_bfloat162*>(k_ptr);
      const __nv_bfloat162 k23 = *reinterpret_cast<const __nv_bfloat162*>(k_ptr + 2);
      const float2 k01f = __bfloat1622float2(k01);
      const float2 k23f = __bfloat1622float2(k23);

      // Partial dot for this lane (Q already pre-scaled)
      float partial = qv0 * k01f.x + qv1 * k01f.y + qv2 * k23f.x + qv3 * k23f.y;

      // Reduce within warp to get full dot
      float dot = warp_sum(partial);

      // Broadcast (scaled) dot from lane 0 (dot already includes sm_scale via pre-scaled Q)
      float scaled = __shfl_sync(FULL_MASK, dot, 0);

      // Online softmax update
      float new_m = fmaxf(m, scaled);
      float old_scale = __expf(m - new_m);
      float w = __expf(scaled - new_m);
      s = s * old_scale + w;

      // Scale previous accumulators by old_scale
      acc0 *= old_scale;
      acc1 *= old_scale;
      acc2 *= old_scale;
      acc3 *= old_scale;

      // Load V fragment and accumulate with weight w
      const __nv_bfloat162 v01 = *reinterpret_cast<const __nv_bfloat162*>(v_ptr);
      const __nv_bfloat162 v23 = *reinterpret_cast<const __nv_bfloat162*>(v_ptr + 2);
      const float2 v01f = __bfloat1622float2(v01);
      const float2 v23f = __bfloat1622float2(v23);
      acc0 += v01f.x * w;
      acc1 += v01f.y * w;
      acc2 += v23f.x * w;
      acc3 += v23f.y * w;

      m = new_m;

      // Advance K/V pointers to next token for the same kv head and lane dim offset
      k_ptr += KV_STRIDE;
      v_ptr += KV_STRIDE;
    }

    // Finalize: out = acc / s; lse = (log(s) + m) / log(2)
    float inv_s = 1.0f / s;
    float o0 = acc0 * inv_s;
    float o1 = acc1 * inv_s;
    float o2 = acc2 * inv_s;
    float o3 = acc3 * inv_s;

    const int64_t out_off = ((int64_t)(q_start + qi) * 32 + h) * HEAD_DIM + d0;
    __nv_bfloat16* out_ptr = out + out_off;
    const __nv_bfloat162 o01 = __floats2bfloat162_rn(o0, o1);
    const __nv_bfloat162 o23 = __floats2bfloat162_rn(o2, o3);
    *reinterpret_cast<__nv_bfloat162*>(out_ptr)       = o01;
    *reinterpret_cast<__nv_bfloat162*>(out_ptr + 2)   = o23;

    if (lane_id == 0) {
      const int64_t lse_off = ((int64_t)(q_start + qi) * 32 + h);
      float lse_val = (s > 0.0f) ? (logf(s) + m) * INV_LOG2 : -CUDART_INF_F;
      lse[lse_off] = lse_val;
    }
  }
}

// Host launcher (called from C++ file compiled with g++)
void launch_gqa_ragged_prefill_causal_h32_kv8_d128(
    const __nv_bfloat16* q,
    const __nv_bfloat16* k,
    const __nv_bfloat16* v,
    const int32_t* qo_indptr,
    const int32_t* kv_indptr,
    int32_t len_indptr,
    float sm_scale,
    __nv_bfloat16* out,
    float* lse,
    cudaStream_t stream) {
  dim3 block(256);
  dim3 grid(static_cast<unsigned>(len_indptr > 0 ? (len_indptr - 1) : 0));
  if (grid.x == 0) return;
  gqa_ragged_prefill_causal_h32_kv8_d128_kernel<<<grid, block, 0, stream>>>(
      q, k, v, qo_indptr, kv_indptr, len_indptr, sm_scale, out, lse);
}

#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <ATen/cuda/CUDAContext.h>
#include <vector>
#include <stdexcept>
#include <sstream>
#include "kernel.h"

static inline void check_cuda_throw(const cudaError_t err, const char* file, int line) {
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA error at " << file << ":" << line << " - " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }
}
#define CHECK_CUDA(err) check_cuda_throw((err), __FILE__, __LINE__)

static inline void tensor_assert(bool cond, const std::string& msg) {
  if (!cond) throw std::invalid_argument(msg);
}

std::vector<torch::Tensor> run(torch::Tensor q,
                               torch::Tensor k,
                               torch::Tensor v,
                               torch::Tensor qo_indptr,
                               torch::Tensor kv_indptr,
                               double sm_scale_double = 0.0) {
  try {
    // Device checks
    tensor_assert(q.device().is_cuda(), "q must be a CUDA tensor");
    tensor_assert(k.device().is_cuda(), "k must be a CUDA tensor");
    tensor_assert(v.device().is_cuda(), "v must be a CUDA tensor");
    tensor_assert(qo_indptr.device().is_cuda(), "qo_indptr must be a CUDA tensor");
    tensor_assert(kv_indptr.device().is_cuda(), "kv_indptr must be a CUDA tensor");

    // Dtype checks
    tensor_assert(q.dtype() == torch::kBFloat16, "q must be bfloat16");
    tensor_assert(k.dtype() == torch::kBFloat16, "k must be bfloat16");
    tensor_assert(v.dtype() == torch::kBFloat16, "v must be bfloat16");
    tensor_assert(qo_indptr.dtype() == torch::kInt32, "qo_indptr must be int32");
    tensor_assert(kv_indptr.dtype() == torch::kInt32, "kv_indptr must be int32");

    // Dim checks
    tensor_assert(q.dim() == 3, "q must be a 3D tensor [total_q, 32, 128]");
    tensor_assert(k.dim() == 3, "k must be a 3D tensor [total_kv, 8, 128]");
    tensor_assert(v.dim() == 3, "v must be a 3D tensor [total_kv, 8, 128]");
    tensor_assert(qo_indptr.dim() == 1, "qo_indptr must be a 1D tensor [len_indptr]");
    tensor_assert(kv_indptr.dim() == 1, "kv_indptr must be a 1D tensor [len_indptr]");

    const int64_t total_q = q.size(0);
    const int64_t num_qo_heads = q.size(1);
    const int64_t head_dim_q = q.size(2);
    const int64_t total_kv = k.size(0);
    const int64_t num_kv_heads = k.size(1);
    const int64_t head_dim_k = k.size(2);
    const int64_t head_dim_v = v.size(2);

    tensor_assert(num_qo_heads == 32, "q second dimension (num_qo_heads) must be 32");
    tensor_assert(num_kv_heads == 8, "k second dimension (num_kv_heads) must be 8");
    tensor_assert(k.size(1) == v.size(1), "k and v must have the same num_kv_heads");
    tensor_assert(head_dim_q == 128, "q head_dim must be 128");
    tensor_assert(head_dim_k == 128 && head_dim_v == 128, "k/v head_dim must be 128");

    tensor_assert(q.is_contiguous(), "q must be contiguous");
    tensor_assert(k.is_contiguous(), "k must be contiguous");
    tensor_assert(v.is_contiguous(), "v must be contiguous");
    tensor_assert(qo_indptr.is_contiguous(), "qo_indptr must be contiguous");
    tensor_assert(kv_indptr.is_contiguous(), "kv_indptr must be contiguous");

    const int64_t len_indptr = qo_indptr.size(0);
    tensor_assert(kv_indptr.size(0) == len_indptr, "qo_indptr and kv_indptr must have the same length");

    // Validate constraints: total_q == qo_indptr[-1], total_kv == kv_indptr[-1]
    int32_t qo_last = 0, kv_last = 0;
    CHECK_CUDA(cudaMemcpy(&qo_last,
                          qo_indptr.data_ptr<int32_t>() + (len_indptr - 1),
                          sizeof(int32_t),
                          cudaMemcpyDeviceToHost));
    CHECK_CUDA(cudaMemcpy(&kv_last,
                          kv_indptr.data_ptr<int32_t>() + (len_indptr - 1),
                          sizeof(int32_t),
                          cudaMemcpyDeviceToHost));
    tensor_assert(static_cast<int64_t>(qo_last) == total_q, "Constraint violation: total_q != qo_indptr[-1]");
    tensor_assert(static_cast<int64_t>(kv_last) == total_kv, "Constraint violation: total_kv != kv_indptr[-1]");

    // Softmax scale
    float sm_scale = (sm_scale_double == 0.0)
          ? (1.0f / std::sqrt(128.0f))
          : static_cast<float>(sm_scale_double);

    // Allocate outputs
    auto out = torch::empty({total_q, num_qo_heads, head_dim_q}, q.options());
    auto lse = torch::empty({total_q, num_qo_heads}, torch::dtype(torch::kFloat32).device(q.device()));

    // Raw pointers
    const __nv_bfloat16* q_ptr = reinterpret_cast<const __nv_bfloat16*>(q.data_ptr<at::BFloat16>());
    const __nv_bfloat16* k_ptr = reinterpret_cast<const __nv_bfloat16*>(k.data_ptr<at::BFloat16>());
    const __nv_bfloat16* v_ptr = reinterpret_cast<const __nv_bfloat16*>(v.data_ptr<at::BFloat16>());
    const int32_t* qo_indptr_ptr = qo_indptr.data_ptr<int32_t>();
    const int32_t* kv_indptr_ptr = kv_indptr.data_ptr<int32_t>();
    __nv_bfloat16* out_ptr = reinterpret_cast<__nv_bfloat16*>(out.data_ptr<at::BFloat16>());
    float* lse_ptr = lse.data_ptr<float>();

    // Launch on the current PyTorch CUDA stream
    cudaStream_t stream = at::cuda::getCurrentCUDAStream().stream();
    launch_gqa_ragged_prefill_causal_h32_kv8_d128(
        q_ptr, k_ptr, v_ptr,
        qo_indptr_ptr, kv_indptr_ptr,
        static_cast<int32_t>(len_indptr),
        sm_scale, out_ptr, lse_ptr,
        stream);

    // Error checking (non-blocking)
    CHECK_CUDA(cudaGetLastError());

    return {out, lse};
  } catch (const std::exception& e) {
    throw;
  }
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "Kernel execution function",
        py::arg("q"),
        py::arg("k"),
        py::arg("v"),
        py::arg("qo_indptr"),
        py::arg("kv_indptr"),
        py::arg("sm_scale") = 0.0);
}
